import React from 'react'
import './style.css'
import { MePhoto } from '../../assets'

const Header = () => (
  <div className='header'>
    <div className='header-desc'>
      <h1>Oscar Eduardo Oceguera Bibriesca</h1>
      <h4>Software Engineer</h4>
      <p>
        Me gusta programar, manejar tecnologías modernas y resolver situaciones relacionadas con esta área. Soy un desarrollador front-end con Javascript y también puedo construir API's con Node.js
      </p>
    </div>
    <img src={MePhoto} alt='me' />
  </div>
)

export default Header



