import React from 'react'
import { NormApp, GHApp } from '../../assets'
import './style.css'

const Fscheck = () => (
  <div className='app'>
    <div className='app-img'>
      <img src={NormApp} alt='norm' width='230px' />
    </div>
    <div className='app-desc'>
      <p>
        <b>Nombre:</b> <span>f-scheck</span>
      </p>
      <p>
        <b>Descripción:</b><br />
        <span>
          Admin para gestionar checklist, esta aplicación usa para el frontend (reactjs,
          redux, redux-sagas, react-router-dom, react-route-redux, create-react-app, immutablejs,
          css-modules, storybook) y en su API esta construida con Nodejs (express, mongoose, mocha, expect).
          En producción el Frontend esta en netlify y el Backend en Heroku.
        </span>
      </p>
      <p>
        <b>Repositorios:</b><br />
        <span>
          <a href='https://github.com/oscaroceguera/norm-admin-desk' target='_blank'>Frontend</a><br />
          <a href='https://github.com/oscaroceguera/norm-admin-api' target='_blank'>Backend</a>
        </span>
      </p>
      <p>
        <b>Cloud: </b>
        <span>
          <a href='https://wonderful-euclid-b9d94a.netlify.com' target='_blank'>Front en producción</a>
        </span>
      </p>
    </div>
  </div>
)

const SearchGH = () => (
  <div className='app'>
    <div className='app-img'>
      <img src={GHApp} alt='gh-app' width='230px' />
    </div>
    <div className='app-desc'>
      <p>
        <b>Nombre:</b> <span>my-repositories-app</span>
      </p>
      <p>
        <b>Descripción:</b><br />
        <span>
          Buscar los repositorios publicos de github por usernama y listar los issues del repositorio seleccionado (reactjs,
          webpack4).
        </span>
      </p>
      <p>
        <b>Repositorios:</b><br />
        <span>
          <a href='https://github.com/oscaroceguera/my-repositories-app' target='_blank'>Frontend</a><br />
        </span>
      </p>
      <p>
        <b>Cloud: </b>
        <span>
          <a href='https://reverent-swanson-de6003.netlify.com' target='_blank'>Front en producción</a>
        </span>
      </p>
    </div>
  </div>
)

const MyApps = () => (
  <div className='my-apps'>
    <h1>Mis apps</h1>
    <div>
      <Fscheck /> <br />
      <SearchGH />
    </div>
  </div>
)

export default MyApps



