import React from 'react'
import PropTypes from 'prop-types'
import './style.css'

const IconLink = ({icon, alt, link, titleLink}) => (
  <a href={link} target='_blank' style={{ display: 'flex', margin: '.5em', width: '250px', textDecoration: 'none'}}>
    <div style={{ marginRight: '.5em' }}>
      <img src={icon} width='24px' alt={alt} />
    </div>
    <span style={{fontSize: '14px', color: 'white'}}>{titleLink}</span>
  </a>
)

IconLink.propTypes = {
  icon: PropTypes.string.isRequired,
  alt: PropTypes.string.isRequired,
  link: PropTypes.string.isRequired,
  titleLink: PropTypes.string.isRequired
}

export default IconLink



