import React from 'react'
import Idle from 'react-idle'
import './style.css'

const IdleComp = () => (
  <Idle
    timeout={3000}
    render={({ idle }) =>
      <div>
        {idle
          ? <h1 className='h1Idle'>{'Hola Mundo!'}</h1>
          : null
        }
      </div>
    }
  />
)

export default IdleComp



