import React from 'react'
import './style.css'
import IconLink from './iconLink'
import {LINKS} from './linksData'

const Section = () => (
  <section className='links'>
    {
      LINKS.map((item, key) => (
        <IconLink
          key={key}
          icon={item.icon}
          alt={item.titleLink}
          link={item.link}
          titleLink={item.titleLink}
        />
      ))
    }
  </section>
)

export default Section



